calculator-webpage.astro_implementation_layout:
// Add to Layout.astro frontmatter (for EN calculator pages):
const webPageSchema = pageType === 'calculator' ? {
  '@context': 'https://schema.org',
  '@type': 'WebPage',
  '@id': `${canonicalUrl}#webpage`,
  url: canonicalUrl,
  name: calcName,
  description: description,
  inLanguage: lang,
  isPartOf: { '@type': 'WebSite', '@id': 'https://cryptocalk.com/#website' },
  datePublished: '2025-11-01',
  dateModified: new Date().toISOString().split('T')[0],
  speakable: {
    '@type': 'SpeakableSpecification',
    cssSelector: ['.calc-header h1', '.calc-header p']
  }
} : null;

// Add to <head>:
{webPageSchema && <script type="application/ld+json" set:html={JSON.stringify(webPageSchema)} />}

calculator-webpage.astro_implementation_localized:
